import { computed } from 'vue'

export function useSortData(
  // 数据源
  dataGetter,
  // 排序选项
  options = {
    key: 'devid', // 排序字段，可以是 'devid', 'code' 等
    order: 'asc', // 排序方向: 'asc'升序, 'desc'降序
    type: 'number' // 排序类型: 'number'数字排序, 'string'字符串排序
  }
) {
  const sortedData = computed(() => {
    const data = dataGetter.value || []
    return [...data].sort((a, b) => {
      const aValue = a[options.key]
      const bValue = b[options.key]

      if (options.type === 'number') {
        // 数字排序
        return options.order === 'asc'
          ? Number(aValue) - Number(bValue) // 升序
          : Number(bValue) - Number(aValue) // 降序
      } else {
        // 字符串排序
        return options.order === 'asc'
          ? String(aValue).localeCompare(String(bValue)) // 升序
          : String(bValue).localeCompare(String(aValue)) // 降序
      }
    })
  })

  return {
    sortedData
  }
}
