<template>
  <div class="flex-direction-column">
    <!-- 每个声卡设备卡片 -->
    <div
      class="g-page-container-with-header"
      v-for="audioitem in sortedAudioData"
      :key="audioitem.devid"
    >
      <div class="container-header flex-space-between">
        <span class="title">{{ audioitem.devdesp }}</span>
      </div>
      <div class="container-content">
        <div class="g-kv-pair" v-for="(label, key) in displayLabels" :key="key">
          <div class="label">{{ label }}</div>
          <div
            class="value"
            :style="key === 'status' ? getStatusTextStyle(audioitem[key]) : {}"
          >
            {{ getDisplayValue(audioitem, key) }}
          </div>
        </div>
      </div>
    </div>

    <!-- 音频文件表格：每个目录一张表 -->
    <div
      class="g-page-container-with-header"
      v-for="group in speechData"
      :key="group.id"
    >
      <div class="container-header">
        <span class="title">{{ group.path }}</span>
      </div>
      <div class="container-content">
        <el-table :data="getSpeechFileRows(group)" style="width: 100%">
          <el-table-column prop="type" label="类型" width="100" />
          <el-table-column prop="desc" label="描述" width="150" />
          <el-table-column prop="path" label="目录" width="250" />
          <el-table-column prop="address" label="地址" width="140" />
          <el-table-column prop="name" label="文件名" />
          <el-table-column label="操作" width="160">
            <template #default="{ row }">
              <el-button size="small" @click="handlePlay(row.id)"
                >播放</el-button
              >
              <el-button
                v-if="row.deletable"
                size="small"
                type="danger"
                @click="handleDelete(row.id)"
              >
                删除
              </el-button>
            </template>
          </el-table-column>
        </el-table>
      </div>
    </div>
  </div>
</template>

<script setup>
import { computed, watch } from 'vue'
import { storeToRefs } from 'pinia'
import { useWslStore } from '@/store/modules/ws.js'
import { useSortData } from '@/hooks/useSortData'
import { useDataMerge } from '@/hooks/useDataMerge'
import { useCommand } from '@/hooks/useCommand'
import { useStatus } from '@/hooks/useStatus'
import { useTimeFormat } from '@/hooks/useTimeFormat'
import { ElMessage } from 'element-plus'

const store = useWslStore()
const { received } = storeToRefs(store)
const { sendAudioCommand } = useCommand(store)
const { getStatusTextStyle } = useStatus()
const { formatTimestamp } = useTimeFormat()

const displayLabels = {
  devid: '设备ID',
  devname: '设备名称',
  devtype: '设备类型',
  devdesp: '设备描述',
  status: '状态',
  timestamp: '时间',
  address: '设备IP地址'
}

const getSpeechFileRows = (group) => {
  const fileList = group.speechFileList || []
  return fileList.map((file) => ({
    ...file,
    type: group.type,
    desc: group.desc,
    path: group.path,
    address: group.address
  }))
}

// 声卡数据
const audioData = useDataMerge(
  computed(() => received.value?.statusData?.audioDataList || []),
  { idField: 'devid' }
).mergedData

const sortedAudioData = useSortData(audioData, {
  key: 'devid',
  type: 'number',
  order: 'asc'
}).sortedData

const speechData = useDataMerge(
  computed(() => received.value?.statusData?.speechDataList || []),
  { idField: 'id' } //
).mergedData

const getDisplayValue = (item, key) => {
  const val = item[key]
  if (key === 'timestamp') {
    return val ? formatTimestamp(val) : '-'
  }
  return val ?? '-'
}

const handlePlay = (id) => {
  sendAudioCommand('PLAY_AUDIO_FILE', id)
}

const handleDelete = (id) => {
  sendAudioCommand('DELETE_AUDIO_FILE', id)
}

watch(
  () => received.value,
  (resp) => {
    if (!resp || resp.command !== 'CMD_RUN_AUDIO_CTRL') return

    const errorCode = resp.errorCode
    const errorMessage = resp.errorMessage

    if (errorCode === 'ERROR_CODE_SUCCESS') {
      ElMessage.success('操作成功')
    } else {
      ElMessage.error(errorMessage || '操作失败')
    }
  },
  { deep: true }
)
</script>

<style lang="less" scoped></style>
